// ═══════════════════════════════════════════════════════════════
// STATE — tracks what's been posted (stored in n8n static data)
// ═══════════════════════════════════════════════════════════════
const workflowStaticData = $getWorkflowStaticData('global');
if (!workflowStaticData.posted) workflowStaticData.posted = {};

// Find next unposted item
const nextPost = QUEUE.find(p => !workflowStaticData.posted[p.id]);

if (!nextPost) {
  return [{ json: { status: 'QUEUE_EMPTY', message: 'All posts have been published! Add new posts to the QUEUE array in the Code node to continue.', brand: BRAND.name, total_posted: Object.keys(workflowStaticData.posted).length } }];
}

const remaining = QUEUE.filter(p => !workflowStaticData.posted[p.id]).length - 1;

return [{
  json: {
    status: 'READY',
    post: nextPost,
    creds: CREDS,
    brand: BRAND,
    remaining_after_this: remaining,
    ig_user_id: BRAND.ig_user_id,
    fb_page_id: BRAND.fb_page_id
  }
}];

// POST SINGLE IMAGE TO INSTAGRAM
const post = $input.first().json.post;
const creds = $input.first().json.creds;
const ig_user_id = $input.first().json.ig_user_id;

const BASE = 'https://graph.facebook.com/v19.0';

async function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function apiPost(url, body, retries = 4) {
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      const response = await $http.request({
        method: 'POST',
        url: url,
        body: body,
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
      });
      return response;
    } catch (err) {
      if (attempt === retries) throw err;
      const wait = 10000 * attempt;
      console.log(`Network hiccup (attempt ${attempt}/${retries}). Retrying in ${wait/1000}s...`);
      await sleep(wait);
    }
  }
}

// Step 1: Create media container
const containerRes = await apiPost(
  `${BASE}/${ig_user_id}/media`,
  `image_url=${encodeURIComponent(post.images[0])}&caption=${encodeURIComponent(post.caption)}&access_token=${creds.ig_token}`
);

const containerId = containerRes.id;
await sleep(3000);

// Step 2: Publish
const publishRes = await apiPost(
  `${BASE}/${ig_user_id}/media_publish`,
  `creation_id=${containerId}&access_token=${creds.ig_token}`
);

return [{
  json: {
    ...($input.first().json),
    ig_post_id: publishRes.id,
    ig_url: `https://www.instagram.com/p/${publishRes.id}/`,
    post_type: 'single'
  }
}];

// POST CAROUSEL TO INSTAGRAM
const post = $input.first().json.post;
const creds = $input.first().json.creds;
const ig_user_id = $input.first().json.ig_user_id;

const BASE = 'https://graph.facebook.com/v19.0';

async function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function apiPost(url, body, retries = 4) {
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      const response = await $http.request({
        method: 'POST',
        url: url,
        body: body,
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
      });
      return response;
    } catch (err) {
      if (attempt === retries) throw err;
      await sleep(10000 * attempt);
    }
  }
}

// Step 1: Upload each image as carousel child
const childIds = [];
for (const imageUrl of post.images) {
  const res = await apiPost(
    `${BASE}/${ig_user_id}/media`,
    `image_url=${encodeURIComponent(imageUrl)}&is_carousel_item=true&access_token=${creds.ig_token}`
  );
  childIds.push(res.id);
  await sleep(2000);
}

// Step 2: Create carousel container
const containerRes = await apiPost(
  `${BASE}/${ig_user_id}/media`,
  `media_type=CAROUSEL&children=${childIds.join(',')}&caption=${encodeURIComponent(post.caption)}&access_token=${creds.ig_token}`
);

await sleep(3000);

// Step 3: Publish
const publishRes = await apiPost(
  `${BASE}/${ig_user_id}/media_publish`,
  `creation_id=${containerRes.id}&access_token=${creds.ig_token}`
);

return [{
  json: {
    ...($input.first().json),
    ig_post_id: publishRes.id,
    ig_url: `https://www.instagram.com/p/${publishRes.id}/`,
    post_type: 'carousel'
  }
}];

// MERGE SINGLE + CAROUSEL RESULTS
// This node receives output from whichever branch ran
const data = $input.first().json;
return [{ json: data }];

// CROSS-POST TO FACEBOOK PAGE
const data = $input.first().json;
const creds = data.creds;
const post = data.post;
const fb_page_id = data.fb_page_id;

const BASE = 'https://graph.facebook.com/v19.0';

try {
  const res = await $http.request({
    method: 'POST',
    url: `${BASE}/${fb_page_id}/photos`,
    body: `url=${encodeURIComponent(post.images[0])}&caption=${encodeURIComponent(post.caption)}&access_token=${creds.fb_token}`,
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
  });

  const fbId = res.post_id || res.id || '';
  const fbUrl = `https://www.facebook.com/${fb_page_id}/posts/${fbId.includes('_') ? fbId.split('_').pop() : fbId}`;

  return [{
    json: {
      ...data,
      fb_post_id: fbId,
      fb_url: fbUrl,
      fb_status: 'posted'
    }
  }];
} catch (err) {
  // Facebook failure is non-fatal — Instagram already posted
  return [{
    json: {
      ...data,
      fb_status: 'skipped',
      fb_error: err.message
    }
  }];
}

// MARK AS POSTED — save to workflow static data so it's never re-posted
const data = $input.first().json;
const workflowStaticData = $getWorkflowStaticData('global');

workflowStaticData.posted[data.post.id] = {
  posted_at: new Date().toISOString(),
  ig_post_id: data.ig_post_id,
  ig_url: data.ig_url,
  fb_url: data.fb_url || null,
  fb_status: data.fb_status
};

const summary = {
  brand: 'HARAMOON',
  label: data.post.label,
  type: data.post_type,
  ig_url: data.ig_url,
  fb_url: data.fb_url || 'skipped',
  fb_status: data.fb_status,
  remaining_in_queue: data.remaining_after_this,
  posted_at: new Date().toISOString(),
  next_action: data.remaining_after_this > 0
    ? `${data.remaining_after_this} post(s) remaining — click Execute again to post the next one`
    : 'Queue is empty! Ask Manus to build a new batch.'
};

return [{ json: summary }];

// QUEUE EMPTY — friendly message
const data = $input.first().json;
return [{
  json: {
    status: 'QUEUE_EMPTY',
    message: data.message,
    total_posted: data.total_posted,
    next_action: 'Open a new Manus chat and say: "Build me a new HARAMOON post batch for n8n" — it will generate a new QUEUE array to paste into the Code node.'
  }
}];
